import{_ as o}from"./data-da5692d0.js";import{_ as t,M as c,p as l,q as i,Q as a,R as s,t as n,N as r,a1 as e}from"./framework-5866ffd3.js";const d={},u=s("h1",{id:"_21分钟mysql基础入门",tabindex:"-1"},[s("a",{class:"header-anchor",href:"#_21分钟mysql基础入门","aria-hidden":"true"},"#"),n(" 21分钟MySQL基础入门")],-1),k=s("p",null,[n("为什么只需要21分钟呢？因为在我们大天朝有句话叫做三七二十一，你可以不管三七二十一开始使用 "),s("code",null,"MySQL"),n(" 及快速的方式入门 "),s("code",null,"MySQL"),n("。其实21分钟把下面语句执行一遍是没有问题的，要理解的话估计不止21分钟，对于初学者来说只需满足自己需求可以增删改查等简易的维护即可。")],-1),m=s("h2",{id:"目录",tabindex:"-1"},[s("a",{class:"header-anchor",href:"#目录","aria-hidden":"true"},"#"),n(" 目录")],-1),v=e('<ul><li><a href="#%E5%BC%80%E5%A7%8B%E4%BD%BF%E7%94%A8">开始使用</a><ul><li><a href="#%E7%99%BB%E5%BD%95mysql">登录MySQL</a></li><li><a href="#%E5%88%9B%E5%BB%BA%E6%95%B0%E6%8D%AE%E5%BA%93">创建数据库</a></li><li><a href="#%E5%88%9B%E5%BB%BA%E6%95%B0%E6%8D%AE%E5%BA%93%E8%A1%A8">创建数据库表</a></li></ul></li><li><a href="#%E5%A2%9E%E5%88%A0%E6%94%B9%E6%9F%A5">增删改查</a><ul><li><a href="#select">SELECT</a></li><li><a href="#update">UPDATE</a></li><li><a href="#insert">INSERT</a></li><li><a href="#delete">DELETE</a></li></ul></li><li><a href="#where">WHERE</a></li><li><a href="#and-or-%E5%92%8C-not">AND, OR 和 NOT</a><ul><li><a href="#and">AND</a></li><li><a href="#or">OR</a></li><li><a href="#not">NOT</a></li><li><a href="#and--or--not">AND &amp; OR &amp; NOT</a></li></ul></li><li><a href="#order-by">ORDER BY</a></li><li><a href="#group-by">GROUP BY</a></li><li><a href="#in">IN</a></li><li><a href="#union">UNION</a></li><li><a href="#between">BETWEEN</a></li><li><a href="#as">AS</a></li><li><a href="#join">JOIN</a><ul><li><a href="#inner-join">INNER JOIN</a></li><li><a href="#left-join">LEFT JOIN</a></li><li><a href="#right-join">RIGHT JOIN</a></li><li><a href="#full-outer-join">FULL OUTER JOIN</a></li></ul></li><li><a href="#sql-%E5%87%BD%E6%95%B0">SQL 函数</a><ul><li><a href="#count">COUNT</a></li><li><a href="#avg">AVG</a></li><li><a href="#sum">SUM</a></li><li><a href="#max">MAX</a></li><li><a href="#min">MIN</a></li></ul></li><li><a href="#%E8%A7%A6%E5%8F%91%E5%99%A8">触发器</a></li><li><a href="#%E6%B7%BB%E5%8A%A0%E7%B4%A2%E5%BC%95">添加索引</a><ul><li><a href="#%E6%99%AE%E9%80%9A%E7%B4%A2%E5%BC%95index">普通索引(INDEX)</a></li><li><a href="#%E4%B8%BB%E9%94%AE%E7%B4%A2%E5%BC%95primary-key">主键索引(PRIMARY key)</a></li><li><a href="#%E5%94%AF%E4%B8%80%E7%B4%A2%E5%BC%95unique">唯一索引(UNIQUE)</a></li><li><a href="#%E5%85%A8%E6%96%87%E7%B4%A2%E5%BC%95fulltext">全文索引(FULLTEXT)</a></li><li><a href="#%E6%B7%BB%E5%8A%A0%E5%A4%9A%E5%88%97%E7%B4%A2%E5%BC%95">添加多列索引</a></li><li><a href="#%E5%BB%BA%E7%AB%8B%E7%B4%A2%E5%BC%95%E7%9A%84%E6%97%B6%E6%9C%BA">建立索引的时机</a></li></ul></li><li><a href="#%E5%88%9B%E5%BB%BA%E5%90%8E%E8%A1%A8%E7%9A%84%E4%BF%AE%E6%94%B9">创建后表的修改</a><ul><li><a href="#%E6%B7%BB%E5%8A%A0%E5%88%97">添加列</a></li><li><a href="#%E4%BF%AE%E6%94%B9%E5%88%97">修改列</a></li><li><a href="#%E5%88%A0%E9%99%A4%E5%88%97">删除列</a></li><li><a href="#%E9%87%8D%E5%91%BD%E5%90%8D%E8%A1%A8">重命名表</a></li><li><a href="#%E6%B8%85%E7%A9%BA%E8%A1%A8%E6%95%B0%E6%8D%AE">清空表数据</a></li><li><a href="#%E5%88%A0%E9%99%A4%E6%95%B4%E5%BC%A0%E8%A1%A8">删除整张表</a></li><li><a href="#%E5%88%A0%E9%99%A4%E6%95%B4%E4%B8%AA%E6%95%B0%E6%8D%AE%E5%BA%93">删除整个数据库</a></li></ul></li><li><a href="#%E5%85%B6%E5%AE%83%E5%AE%9E%E4%BE%8B">其它实例</a><ul><li><a href="#sql%E5%88%A0%E9%99%A4%E9%87%8D%E5%A4%8D%E8%AE%B0%E5%BD%95">SQL删除重复记录</a></li></ul></li><li><a href="#%E5%8F%82%E8%80%83%E6%89%8B%E5%86%8C">参考手册</a></li></ul>',1),b=e('<h2 id="开始使用" tabindex="-1"><a class="header-anchor" href="#开始使用" aria-hidden="true">#</a> 开始使用</h2><p>我下面所有的SQL语句是基于MySQL 5.6+运行。</p><p>MySQL 为关系型数据库(Relational Database Management System)，一个关系型数据库由一个或数个表格组成, 如图所示的一个表格：</p><img alt="21分钟MySQL基础入门" height="221" src="'+o+`"><ul><li><code>表头(header)</code>: 每一列的名称;</li><li><code>列(col)</code>: 具有相同数据类型的数据的集合;</li><li><code>行(row)</code>: 每一行用来描述某个人/物的具体信息;</li><li><code>值(value)</code>: 行的具体信息, 每个值必须与该列的数据类型相同;</li><li><code>键(key)</code>: 表中用来识别某个特定的人\\物的方法, 键的值在当前列中具有唯一性。</li></ul><h3 id="登录mysql" tabindex="-1"><a class="header-anchor" href="#登录mysql" aria-hidden="true">#</a> 登录MySQL</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>mysql <span class="token parameter variable">-h</span> <span class="token number">127.0</span>.0.1 <span class="token parameter variable">-u</span> <span class="token operator">&lt;</span>用户名<span class="token operator">&gt;</span> -p<span class="token operator">&lt;</span>密码<span class="token operator">&gt;</span>.   <span class="token comment"># 默认用户名&lt;root&gt;，-p 是密码，⚠️参数后面不需要空格</span>
mysql <span class="token parameter variable">-D</span> 所选择的数据库名 <span class="token parameter variable">-h</span> 主机名 <span class="token parameter variable">-u</span> 用户名 <span class="token parameter variable">-p</span>
mysql<span class="token operator">&gt;</span> <span class="token builtin class-name">exit</span> <span class="token comment"># 退出 使用 “quit;” 或 “\\q;” 一样的效果</span>
mysql<span class="token operator">&gt;</span> status<span class="token punctuation">;</span>  <span class="token comment"># 显示当前mysql的version的各种信息</span>
mysql<span class="token operator">&gt;</span> <span class="token keyword">select</span> version<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment"># 显示当前mysql的version信息</span>
mysql<span class="token operator">&gt;</span> show global variables like <span class="token string">&#39;port&#39;</span><span class="token punctuation">;</span> <span class="token comment"># 查看MySQL端口号</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="创建数据库" tabindex="-1"><a class="header-anchor" href="#创建数据库" aria-hidden="true">#</a> 创建数据库</h3><p>对于表的操作需要先进入库<code>use 库名;</code></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 创建一个名为 samp_db 的数据库，数据库字符编码指定为 gbk</span>
<span class="token keyword">create</span> <span class="token keyword">database</span> samp_db <span class="token keyword">character</span> <span class="token keyword">set</span> gbk<span class="token punctuation">;</span>
<span class="token keyword">drop</span> <span class="token keyword">database</span> samp_db<span class="token punctuation">;</span> <span class="token comment">-- 删除 库名为 samp_db 的库</span>
<span class="token keyword">show</span> <span class="token keyword">databases</span><span class="token punctuation">;</span>        <span class="token comment">-- 显示数据库列表。</span>
<span class="token keyword">use</span> samp_db<span class="token punctuation">;</span>           <span class="token comment">-- 选择创建的数据库 samp_db </span>
<span class="token keyword">show</span> <span class="token keyword">tables</span><span class="token punctuation">;</span>           <span class="token comment">-- 显示 samp_db 下面所有的表名字</span>
<span class="token keyword">describe</span> 表名<span class="token punctuation">;</span>          <span class="token comment">-- 显示数据表的结构</span>
<span class="token keyword">delete</span> <span class="token keyword">from</span> 表名<span class="token punctuation">;</span>       <span class="token comment">-- 清空表中记录</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="创建数据库表" tabindex="-1"><a class="header-anchor" href="#创建数据库表" aria-hidden="true">#</a> 创建数据库表</h3><blockquote><p><code>CREATE TABLE 语法</code> 语句用于从表中选取数据。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> 表名称 <span class="token punctuation">(</span>
  列名称<span class="token number">1</span>  数据类型<span class="token punctuation">,</span>
  列名称<span class="token number">2</span>  数据类型<span class="token punctuation">,</span>
  列名称<span class="token number">3</span>  数据类型<span class="token punctuation">,</span>
  <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 如果数据库中存在user_accounts表，就把它从数据库中drop掉</span>
<span class="token keyword">DROP</span> <span class="token keyword">TABLE</span> <span class="token keyword">IF</span> <span class="token keyword">EXISTS</span> <span class="token identifier"><span class="token punctuation">\`</span>user_accounts<span class="token punctuation">\`</span></span><span class="token punctuation">;</span>
<span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> <span class="token identifier"><span class="token punctuation">\`</span>user_accounts<span class="token punctuation">\`</span></span> <span class="token punctuation">(</span>
  <span class="token identifier"><span class="token punctuation">\`</span>id<span class="token punctuation">\`</span></span>             <span class="token keyword">int</span><span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">)</span> <span class="token keyword">unsigned</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token keyword">AUTO_INCREMENT</span> <span class="token keyword">primary</span> <span class="token keyword">key</span><span class="token punctuation">,</span>
  <span class="token identifier"><span class="token punctuation">\`</span>password<span class="token punctuation">\`</span></span>       <span class="token keyword">varchar</span><span class="token punctuation">(</span><span class="token number">32</span><span class="token punctuation">)</span>       <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token keyword">DEFAULT</span> <span class="token string">&#39;&#39;</span> <span class="token keyword">COMMENT</span> <span class="token string">&#39;用户密码&#39;</span><span class="token punctuation">,</span>
  <span class="token identifier"><span class="token punctuation">\`</span>reset_password<span class="token punctuation">\`</span></span> <span class="token keyword">tinyint</span><span class="token punctuation">(</span><span class="token number">32</span><span class="token punctuation">)</span>       <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token keyword">DEFAULT</span> <span class="token number">0</span> <span class="token keyword">COMMENT</span> <span class="token string">&#39;用户类型：0－不需要重置密码；1-需要重置密码&#39;</span><span class="token punctuation">,</span>
  <span class="token identifier"><span class="token punctuation">\`</span>mobile<span class="token punctuation">\`</span></span>         <span class="token keyword">varchar</span><span class="token punctuation">(</span><span class="token number">20</span><span class="token punctuation">)</span>       <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token keyword">DEFAULT</span> <span class="token string">&#39;&#39;</span> <span class="token keyword">COMMENT</span> <span class="token string">&#39;手机&#39;</span><span class="token punctuation">,</span>
  <span class="token identifier"><span class="token punctuation">\`</span>create_at<span class="token punctuation">\`</span></span>      <span class="token keyword">timestamp</span><span class="token punctuation">(</span><span class="token number">6</span><span class="token punctuation">)</span>      <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token keyword">DEFAULT</span> <span class="token keyword">CURRENT_TIMESTAMP</span><span class="token punctuation">(</span><span class="token number">6</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  <span class="token identifier"><span class="token punctuation">\`</span>update_at<span class="token punctuation">\`</span></span>      <span class="token keyword">timestamp</span><span class="token punctuation">(</span><span class="token number">6</span><span class="token punctuation">)</span>      <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token keyword">DEFAULT</span> <span class="token keyword">CURRENT_TIMESTAMP</span><span class="token punctuation">(</span><span class="token number">6</span><span class="token punctuation">)</span> <span class="token keyword">ON</span> <span class="token keyword">UPDATE</span> <span class="token keyword">CURRENT_TIMESTAMP</span><span class="token punctuation">(</span><span class="token number">6</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  <span class="token comment">-- 创建唯一索引，不允许重复</span>
  <span class="token keyword">UNIQUE</span> <span class="token keyword">INDEX</span> idx_user_mobile<span class="token punctuation">(</span><span class="token identifier"><span class="token punctuation">\`</span>mobile<span class="token punctuation">\`</span></span><span class="token punctuation">)</span>
<span class="token punctuation">)</span>
<span class="token keyword">ENGINE</span><span class="token operator">=</span><span class="token keyword">InnoDB</span> <span class="token keyword">DEFAULT</span> <span class="token keyword">CHARSET</span><span class="token operator">=</span>utf8
<span class="token keyword">COMMENT</span><span class="token operator">=</span><span class="token string">&#39;用户表信息&#39;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>数据类型的属性解释</p><ul><li><code>NULL</code>：数据列可包含NULL值；</li><li><code>NOT NULL</code>：数据列不允许包含NULL值；</li><li><code>DEFAULT</code>：默认值；</li><li><code>PRIMARY KEY</code>：主键；</li><li><code>AUTO_INCREMENT</code>：自动递增，适用于整数类型；</li><li><code>UNSIGNED</code>：是指数值类型只能为正数；</li><li><code>CHARACTER SET name</code>：指定一个字符集；</li><li><code>COMMENT</code>：对表或者字段说明；</li></ul><h3 id="删除数据库表" tabindex="-1"><a class="header-anchor" href="#删除数据库表" aria-hidden="true">#</a> 删除数据库表</h3><blockquote><p><code>DROP/TRUNCATE TABLE 语法</code> 语句用于删除数据库中的现有表。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">DROP</span> <span class="token keyword">TABLE</span> 表名称<span class="token punctuation">;</span>     <span class="token comment">-- 用于删除数据库中的现有表。</span>
<span class="token keyword">TRUNCATE</span> <span class="token keyword">TABLE</span> 表名称<span class="token punctuation">;</span> <span class="token comment">-- 用于删除表内的数据，但不删除表本身。</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 删除现有表 Shippers：</span>
<span class="token keyword">DROP</span> <span class="token keyword">TABLE</span> Shippers<span class="token punctuation">;</span>
<span class="token comment">-- 删除现有表 Shippers 表内的数据，不删除表：</span>
<span class="token keyword">TRUNCATE</span> <span class="token keyword">TABLE</span> Shippers<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="增删改查" tabindex="-1"><a class="header-anchor" href="#增删改查" aria-hidden="true">#</a> 增删改查</h2><h3 id="select" tabindex="-1"><a class="header-anchor" href="#select" aria-hidden="true">#</a> SELECT</h3><blockquote><p><code>SELECT 语法</code> 语句用于从表中选取数据。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> 列名称<span class="token number">1</span><span class="token punctuation">,</span> 列名称<span class="token number">2</span><span class="token punctuation">,</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span> <span class="token keyword">FROM</span> 表名称<span class="token punctuation">;</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> 表名称<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 从 Customers 表中选择 CustomerName 和 City 列：</span>
<span class="token keyword">SELECT</span> CustomerName<span class="token punctuation">,</span> City <span class="token keyword">FROM</span> Customers<span class="token punctuation">;</span>
<span class="token comment">-- 从 Customers 表中选择所有列：</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Customers<span class="token punctuation">;</span>
<span class="token comment">-- 表 station 取个别名叫 s，表 station 中不包含 字段 id=13 或者 14 的，并且 id 不等于 4 的 查询出来，只显示 id</span>
<span class="token keyword">SELECT</span> s<span class="token punctuation">.</span>id <span class="token keyword">from</span> station s <span class="token keyword">WHERE</span> id <span class="token operator">in</span> <span class="token punctuation">(</span><span class="token number">13</span><span class="token punctuation">,</span><span class="token number">14</span><span class="token punctuation">)</span> <span class="token operator">and</span> id <span class="token operator">not</span> <span class="token operator">in</span> <span class="token punctuation">(</span><span class="token number">4</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">-- 从表 users 选取 id=3 的数据，并只拉一条数据(据说能优化性能)</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> users <span class="token keyword">where</span> id<span class="token operator">=</span><span class="token number">3</span> <span class="token keyword">limit</span> <span class="token number">1</span>
<span class="token comment">-- 结果集中会自动去重复数据</span>
<span class="token keyword">SELECT</span> <span class="token keyword">DISTINCT</span> Company <span class="token keyword">FROM</span> Orders 
<span class="token comment">-- 表 Persons 字段 Id_P 等于 Orders 字段 Id_P 的值，</span>
<span class="token comment">-- 结果集显示 Persons表的 LastName、FirstName字段，Orders表的OrderNo字段</span>
<span class="token keyword">SELECT</span> p<span class="token punctuation">.</span>LastName<span class="token punctuation">,</span> p<span class="token punctuation">.</span>FirstName<span class="token punctuation">,</span> o<span class="token punctuation">.</span>OrderNo <span class="token keyword">FROM</span> Persons p<span class="token punctuation">,</span> Orders o <span class="token keyword">WHERE</span> p<span class="token punctuation">.</span>Id_P <span class="token operator">=</span> o<span class="token punctuation">.</span>Id_P

<span class="token comment">-- gbk 和 utf8 中英文混合排序最简单的办法 </span>
<span class="token comment">-- ci是 case insensitive, 即 “大小写不敏感”</span>
<span class="token keyword">SELECT</span> tag<span class="token punctuation">,</span> <span class="token function">COUNT</span><span class="token punctuation">(</span>tag<span class="token punctuation">)</span> <span class="token keyword">from</span> news <span class="token keyword">GROUP</span> <span class="token keyword">BY</span> tag <span class="token keyword">order</span> <span class="token keyword">by</span> <span class="token keyword">convert</span><span class="token punctuation">(</span>tag <span class="token keyword">using</span> gbk<span class="token punctuation">)</span> <span class="token keyword">collate</span> gbk_chinese_ci<span class="token punctuation">;</span>
<span class="token keyword">SELECT</span> tag<span class="token punctuation">,</span> <span class="token function">COUNT</span><span class="token punctuation">(</span>tag<span class="token punctuation">)</span> <span class="token keyword">from</span> news <span class="token keyword">GROUP</span> <span class="token keyword">BY</span> tag <span class="token keyword">order</span> <span class="token keyword">by</span> <span class="token keyword">convert</span><span class="token punctuation">(</span>tag <span class="token keyword">using</span> utf8<span class="token punctuation">)</span> <span class="token keyword">collate</span> utf8_unicode_ci<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="update" tabindex="-1"><a class="header-anchor" href="#update" aria-hidden="true">#</a> UPDATE</h3><blockquote><p><code>Update 语法</code> 语句用于修改表中的数据。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">UPDATE</span> 表名称 <span class="token keyword">SET</span> 列名称<span class="token number">1</span> <span class="token operator">=</span> 值<span class="token number">1</span><span class="token punctuation">,</span> 列名称<span class="token number">2</span> <span class="token operator">=</span> 值<span class="token number">2</span><span class="token punctuation">,</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span> <span class="token keyword">WHERE</span> 条件<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- update语句设置字段值为另一个结果取出来的字段</span>
<span class="token keyword">UPDATE</span> <span class="token keyword">user</span> <span class="token keyword">set</span> name <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token keyword">SELECT</span> name <span class="token keyword">from</span> user1 <span class="token keyword">WHERE</span> user1 <span class="token punctuation">.</span>id <span class="token operator">=</span> <span class="token number">1</span> <span class="token punctuation">)</span>
<span class="token keyword">WHERE</span> id <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token keyword">SELECT</span> id <span class="token keyword">from</span> user2 <span class="token keyword">WHERE</span> user2 <span class="token punctuation">.</span>name<span class="token operator">=</span><span class="token string">&#39;小苏&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">-- 更新表 orders 中 id=1 的那一行数据更新它的 title 字段</span>
<span class="token keyword">UPDATE</span> <span class="token identifier"><span class="token punctuation">\`</span>orders<span class="token punctuation">\`</span></span> <span class="token keyword">set</span> title<span class="token operator">=</span><span class="token string">&#39;这里是标题&#39;</span> <span class="token keyword">WHERE</span> id<span class="token operator">=</span><span class="token number">1</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="insert" tabindex="-1"><a class="header-anchor" href="#insert" aria-hidden="true">#</a> INSERT</h3><blockquote><p><code>INSERT 语法</code> 用于向表格中插入新的行。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> 表名称 <span class="token punctuation">(</span>列名称<span class="token number">1</span><span class="token punctuation">,</span> 列名称<span class="token number">2</span><span class="token punctuation">,</span> 列名称<span class="token number">3</span><span class="token punctuation">,</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">)</span> <span class="token keyword">VALUES</span> <span class="token punctuation">(</span>值<span class="token number">1</span><span class="token punctuation">,</span> 值<span class="token number">2</span><span class="token punctuation">,</span> 值<span class="token number">3</span><span class="token punctuation">,</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> 表名称 <span class="token keyword">VALUES</span> <span class="token punctuation">(</span>值<span class="token number">1</span><span class="token punctuation">,</span> 值<span class="token number">2</span><span class="token punctuation">,</span> 值<span class="token number">3</span><span class="token punctuation">,</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 向表 Persons 插入一条字段 LastName = JSLite 字段 Address = shanghai</span>
<span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> Persons <span class="token punctuation">(</span>LastName<span class="token punctuation">,</span> Address<span class="token punctuation">)</span> <span class="token keyword">VALUES</span> <span class="token punctuation">(</span><span class="token string">&#39;JSLite&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;shanghai&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">-- 向表 meeting 插入 字段 a=1 和字段 b=2</span>
<span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> meeting <span class="token keyword">SET</span> a<span class="token operator">=</span><span class="token number">1</span><span class="token punctuation">,</span>b<span class="token operator">=</span><span class="token number">2</span><span class="token punctuation">;</span>
<span class="token comment">-- </span>
<span class="token comment">-- SQL实现将一个表的数据插入到另外一个表的代码</span>
<span class="token comment">-- 如果只希望导入指定字段，可以用这种方法：</span>
<span class="token comment">-- INSERT INTO 目标表 (字段1, 字段2, ...) SELECT 字段1, 字段2, ... FROM 来源表;</span>
<span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> orders <span class="token punctuation">(</span>user_account_id<span class="token punctuation">,</span> title<span class="token punctuation">)</span> <span class="token keyword">SELECT</span> m<span class="token punctuation">.</span>user_id<span class="token punctuation">,</span> m<span class="token punctuation">.</span>title <span class="token keyword">FROM</span> meeting m <span class="token keyword">where</span> m<span class="token punctuation">.</span>id<span class="token operator">=</span><span class="token number">1</span><span class="token punctuation">;</span>

<span class="token comment">-- 向表 charger 插入一条数据，已存在就对表 charger 更新 \`type\`,\`update_at\` 字段；</span>
<span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> <span class="token identifier"><span class="token punctuation">\`</span>charger<span class="token punctuation">\`</span></span> <span class="token punctuation">(</span><span class="token identifier"><span class="token punctuation">\`</span>id<span class="token punctuation">\`</span></span><span class="token punctuation">,</span><span class="token identifier"><span class="token punctuation">\`</span>type<span class="token punctuation">\`</span></span><span class="token punctuation">,</span><span class="token identifier"><span class="token punctuation">\`</span>create_at<span class="token punctuation">\`</span></span><span class="token punctuation">,</span><span class="token identifier"><span class="token punctuation">\`</span>update_at<span class="token punctuation">\`</span></span><span class="token punctuation">)</span> <span class="token keyword">VALUES</span> <span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">,</span><span class="token number">2</span><span class="token punctuation">,</span><span class="token string">&#39;2017-05-18 11:06:17&#39;</span><span class="token punctuation">,</span><span class="token string">&#39;2017-05-18 11:06:17&#39;</span><span class="token punctuation">)</span> <span class="token keyword">ON</span> <span class="token keyword">DUPLICATE</span> <span class="token keyword">KEY</span> <span class="token keyword">UPDATE</span> <span class="token identifier"><span class="token punctuation">\`</span>id<span class="token punctuation">\`</span></span><span class="token operator">=</span><span class="token keyword">VALUES</span><span class="token punctuation">(</span><span class="token identifier"><span class="token punctuation">\`</span>id<span class="token punctuation">\`</span></span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token identifier"><span class="token punctuation">\`</span>type<span class="token punctuation">\`</span></span><span class="token operator">=</span><span class="token keyword">VALUES</span><span class="token punctuation">(</span><span class="token identifier"><span class="token punctuation">\`</span>type<span class="token punctuation">\`</span></span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token identifier"><span class="token punctuation">\`</span>update_at<span class="token punctuation">\`</span></span><span class="token operator">=</span><span class="token keyword">VALUES</span><span class="token punctuation">(</span><span class="token identifier"><span class="token punctuation">\`</span>update_at<span class="token punctuation">\`</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="delete" tabindex="-1"><a class="header-anchor" href="#delete" aria-hidden="true">#</a> DELETE</h3><blockquote><p><code>DELETE 语法</code> 语句用于删除表中的现有记录。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">DELETE</span> <span class="token keyword">FROM</span> 表名称 <span class="token keyword">WHERE</span> 条件<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 在不删除table_name表的情况下删除所有的行，清空表。</span>
<span class="token keyword">DELETE</span> <span class="token keyword">FROM</span> table_name
<span class="token comment">-- 或者</span>
<span class="token keyword">DELETE</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> table_name
<span class="token comment">-- 删除 Person 表字段 LastName = &#39;JSLite&#39; </span>
<span class="token keyword">DELETE</span> <span class="token keyword">FROM</span> Person <span class="token keyword">WHERE</span> LastName <span class="token operator">=</span> <span class="token string">&#39;JSLite&#39;</span> 
<span class="token comment">-- 删除 表meeting id 为2和3的两条数据</span>
<span class="token keyword">DELETE</span> <span class="token keyword">from</span> meeting <span class="token keyword">where</span> id <span class="token operator">in</span> <span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">,</span><span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="where" tabindex="-1"><a class="header-anchor" href="#where" aria-hidden="true">#</a> WHERE</h2><blockquote><p><code>WHERE 语法</code> 用于仅提取满足指定条件的记录</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> 列名称<span class="token punctuation">,</span> 列名称<span class="token punctuation">,</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span> <span class="token keyword">FROM</span> 表名称 <span class="token keyword">WHERE</span> 条件<span class="token number">1</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 从表 Persons 中选出 Year 字段大于 1965 的数据</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Persons <span class="token keyword">WHERE</span> <span class="token keyword">Year</span><span class="token operator">&gt;</span><span class="token number">1965</span>
<span class="token comment">-- 从 Customers 表中选择 Country = Mexico 的所有数据：</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Customers <span class="token keyword">WHERE</span> Country<span class="token operator">=</span><span class="token string">&#39;Mexico&#39;</span><span class="token punctuation">;</span>
<span class="token comment">-- 从 Customers 表中选择 CustomerID = 1 的所有数据：</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Customers <span class="token keyword">WHERE</span> CustomerID<span class="token operator">=</span><span class="token number">1</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="and-or-和-not" tabindex="-1"><a class="header-anchor" href="#and-or-和-not" aria-hidden="true">#</a> AND, OR 和 NOT</h2><p><code>WHERE</code> 子句可以与 <code>AND</code>、<code>OR</code> 和 <code>NOT</code> 运算符组合使用。</p><p><code>AND</code> 和 <code>OR</code> 运算符用于根据多个条件过滤记录：</p><ul><li>如果由 <code>AND</code> 分隔的所有条件都为 <code>TRUE</code>，则 <code>AND</code> 运算符将显示一条记录。</li><li>如果由 <code>OR</code> 分隔的任何条件为 <code>TRUE</code>，则 <code>OR</code> 运算符将显示一条记录。</li></ul><p>如果条件不为真，<code>NOT</code> 运算符将显示一条记录。</p><h3 id="and" tabindex="-1"><a class="header-anchor" href="#and" aria-hidden="true">#</a> AND</h3><blockquote><p><code>AND 语法</code></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> 列名称<span class="token punctuation">,</span> 列名称<span class="token punctuation">,</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span> <span class="token keyword">FROM</span> 表名称 <span class="token keyword">WHERE</span> 条件<span class="token number">1</span> <span class="token operator">AND</span> 条件<span class="token number">2</span> <span class="token operator">AND</span> 条件<span class="token number">3</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 删除 meeting 表字段 </span>
<span class="token comment">-- id=2 并且 user_id=5 的数据  和</span>
<span class="token comment">-- id=3 并且 user_id=6 的数据 </span>
<span class="token keyword">DELETE</span> <span class="token keyword">from</span> meeting <span class="token keyword">where</span> id <span class="token operator">in</span> <span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">,</span><span class="token number">3</span><span class="token punctuation">)</span> <span class="token operator">and</span> user_id <span class="token operator">in</span> <span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">,</span><span class="token number">6</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">-- 使用 AND 来显示所有姓为 &quot;Carter&quot; 并且名为 &quot;Thomas&quot; 的人：</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Persons <span class="token keyword">WHERE</span> FirstName<span class="token operator">=</span><span class="token string">&#39;Thomas&#39;</span> <span class="token operator">AND</span> LastName<span class="token operator">=</span><span class="token string">&#39;Carter&#39;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="or" tabindex="-1"><a class="header-anchor" href="#or" aria-hidden="true">#</a> OR</h3><blockquote><p><code>OR 语法</code></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> 列名称<span class="token number">1</span><span class="token punctuation">,</span> 列名称<span class="token number">2</span><span class="token punctuation">,</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span> <span class="token keyword">FROM</span> 表名称 <span class="token keyword">WHERE</span> 条件<span class="token number">1</span> <span class="token operator">OR</span> 条件<span class="token number">2</span> <span class="token operator">OR</span> 条件<span class="token number">3</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 使用 OR 来显示所有姓为 &quot;Carter&quot; 或者名为 &quot;Thomas&quot; 的人：</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Persons <span class="token keyword">WHERE</span> firstname<span class="token operator">=</span><span class="token string">&#39;Thomas&#39;</span> <span class="token operator">OR</span> lastname<span class="token operator">=</span><span class="token string">&#39;Carter&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="not" tabindex="-1"><a class="header-anchor" href="#not" aria-hidden="true">#</a> NOT</h3><blockquote><p><code>NOT 语法</code></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> 列名称<span class="token number">1</span><span class="token punctuation">,</span> 列名称<span class="token number">2</span><span class="token punctuation">,</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span> <span class="token keyword">FROM</span> 表名称 <span class="token keyword">WHERE</span> <span class="token operator">NOT</span> 条件<span class="token number">2</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 从 Customers 表中选择 Country 不是 Germany 的所有字段：</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Customers <span class="token keyword">WHERE</span> <span class="token operator">NOT</span> Country<span class="token operator">=</span><span class="token string">&#39;Germany&#39;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="and-or-not" tabindex="-1"><a class="header-anchor" href="#and-or-not" aria-hidden="true">#</a> AND &amp; OR &amp; NOT</h3><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 从 Customers 表中选择所有字段，其中 Country 为 Germany 且城市必须为 Berlin 或 München（使用括号构成复杂表达式）：</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Customers <span class="token keyword">WHERE</span> Country<span class="token operator">=</span><span class="token string">&#39;Germany&#39;</span> <span class="token operator">AND</span> <span class="token punctuation">(</span>City<span class="token operator">=</span><span class="token string">&#39;Berlin&#39;</span> <span class="token operator">OR</span> City<span class="token operator">=</span><span class="token string">&#39;München&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">-- 从 Customers 表中选择 Country 不是 Germany 和 NOT &quot;USA&quot; 的所有字段：</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Customers <span class="token keyword">WHERE</span> <span class="token operator">NOT</span> Country<span class="token operator">=</span><span class="token string">&#39;Germany&#39;</span> <span class="token operator">AND</span> <span class="token operator">NOT</span> Country<span class="token operator">=</span><span class="token string">&#39;USA&#39;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="order-by" tabindex="-1"><a class="header-anchor" href="#order-by" aria-hidden="true">#</a> ORDER BY</h2><blockquote><p><code>ORDER BY 语法</code> 用于按升序或降序对结果集进行排序。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> 列名称<span class="token number">1</span><span class="token punctuation">,</span> 列名称<span class="token number">2</span><span class="token punctuation">,</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span> <span class="token keyword">FROM</span> 表名称 <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> 列名称<span class="token number">1</span><span class="token punctuation">,</span> 列名称<span class="token number">2</span><span class="token punctuation">,</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span> <span class="token keyword">ASC</span><span class="token operator">|</span><span class="token keyword">DESC</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>默认按 <code>ASC</code> 升序对记录进行排序。要按降序对记录进行排序，请使用 <code>DESC</code> 关键字。</p></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 从 Customers 表中选择所有字段，按 Country 列排序：</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Customers <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> Country<span class="token punctuation">;</span>
<span class="token comment">-- 从 Orders 表中选择 Company, OrderNumber 字段，按 Company 列排序：</span>
<span class="token keyword">SELECT</span> Company<span class="token punctuation">,</span> OrderNumber <span class="token keyword">FROM</span> Orders <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> Company
<span class="token comment">-- 从 Orders 表中选择 Company, OrderNumber 字段，按 Company 列降序排序：</span>
<span class="token keyword">SELECT</span> Company<span class="token punctuation">,</span> OrderNumber <span class="token keyword">FROM</span> Orders <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> Company <span class="token keyword">DESC</span>
<span class="token comment">-- 从 Orders 表中选择 Company, OrderNumber 字段，按 Company 列降序排序，并 OrderNumber 以顺序显示：</span>
<span class="token keyword">SELECT</span> Company<span class="token punctuation">,</span> OrderNumber <span class="token keyword">FROM</span> Orders <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> Company <span class="token keyword">DESC</span><span class="token punctuation">,</span> OrderNumber <span class="token keyword">ASC</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="group-by" tabindex="-1"><a class="header-anchor" href="#group-by" aria-hidden="true">#</a> GROUP BY</h2><blockquote><p><code>GROUP BY 语法</code> 将具有相同值的行分组到汇总行中</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> 列名称<span class="token punctuation">(</span>s<span class="token punctuation">)</span>
<span class="token keyword">FROM</span> 表名称
<span class="token keyword">WHERE</span> 条件
<span class="token keyword">GROUP</span> <span class="token keyword">BY</span> 列名称<span class="token punctuation">(</span>s<span class="token punctuation">)</span>
<span class="token keyword">ORDER</span> <span class="token keyword">BY</span> 列名称<span class="token punctuation">(</span>s<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 列出了 Orders 每个发货人 Shippers 发送的订单 Orders 数量</span>
<span class="token keyword">SELECT</span> Shippers<span class="token punctuation">.</span>ShipperName<span class="token punctuation">,</span> <span class="token function">COUNT</span><span class="token punctuation">(</span>Orders<span class="token punctuation">.</span>OrderID<span class="token punctuation">)</span> <span class="token keyword">AS</span> NumberOfOrders <span class="token keyword">FROM</span> Orders
<span class="token keyword">LEFT</span> <span class="token keyword">JOIN</span> Shippers <span class="token keyword">ON</span> Orders<span class="token punctuation">.</span>ShipperID <span class="token operator">=</span> Shippers<span class="token punctuation">.</span>ShipperID
<span class="token keyword">GROUP</span> <span class="token keyword">BY</span> ShipperName<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="in" tabindex="-1"><a class="header-anchor" href="#in" aria-hidden="true">#</a> IN</h2><blockquote><p><code>IN 语法</code> 运算符允许您在 WHERE 子句中指定多个值。运算符是多个 OR 条件的简写。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> 列名称<span class="token punctuation">(</span>s<span class="token punctuation">)</span> <span class="token keyword">FROM</span> 表名称 <span class="token keyword">WHERE</span> 列名称 <span class="token operator">IN</span> <span class="token punctuation">(</span>值<span class="token number">1</span><span class="token punctuation">,</span> 值<span class="token number">2</span><span class="token punctuation">,</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">SELECT</span> 列名称<span class="token punctuation">(</span>s<span class="token punctuation">)</span> <span class="token keyword">FROM</span> 表名称 <span class="token keyword">WHERE</span> 列名称 <span class="token operator">IN</span> <span class="token punctuation">(</span><span class="token keyword">SELECT</span> STATEMENT<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 从表 Persons 选取 字段 LastName 等于 Adams、Carter</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Persons <span class="token keyword">WHERE</span> LastName <span class="token operator">IN</span> <span class="token punctuation">(</span><span class="token string">&#39;Adams&#39;</span><span class="token punctuation">,</span><span class="token string">&#39;Carter&#39;</span><span class="token punctuation">)</span>
<span class="token comment">-- 从表 Customers 选取 Country 值为 &#39;Germany&#39;, &#39;France&#39;, &#39;UK&#39; 的所有数据</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Customers <span class="token keyword">WHERE</span> Country <span class="token operator">IN</span> <span class="token punctuation">(</span><span class="token string">&#39;Germany&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;France&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;UK&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">-- 从表 Customers 选取 Country 值不为 &#39;Germany&#39;, &#39;France&#39;, &#39;UK&#39; 的所有数据</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Customers <span class="token keyword">WHERE</span> Country <span class="token operator">NOT</span> <span class="token operator">IN</span> <span class="token punctuation">(</span><span class="token string">&#39;Germany&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;France&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;UK&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">-- 从表 Customers 选取与 Suppliers 表 Country 字段相同的所有数据：</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Customers <span class="token keyword">WHERE</span> Country <span class="token operator">IN</span> <span class="token punctuation">(</span><span class="token keyword">SELECT</span> Country <span class="token keyword">FROM</span> Suppliers<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="union" tabindex="-1"><a class="header-anchor" href="#union" aria-hidden="true">#</a> UNION</h2><blockquote><p><code>UNION 语法</code> 操作符用于合并两个或多个 SELECT 语句的结果集</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> 列名称<span class="token punctuation">(</span>s<span class="token punctuation">)</span> <span class="token keyword">FROM</span> 表名称<span class="token number">1</span>
<span class="token keyword">UNION</span>
<span class="token keyword">SELECT</span> 列名称<span class="token punctuation">(</span>s<span class="token punctuation">)</span> <span class="token keyword">FROM</span> 表名称<span class="token number">2</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 列出所有在中国表（Employees_China）和美国（Employees_USA）的不同的雇员名</span>
<span class="token keyword">SELECT</span> E_Name <span class="token keyword">FROM</span> Employees_China <span class="token keyword">UNION</span> <span class="token keyword">SELECT</span> E_Name <span class="token keyword">FROM</span> Employees_USA

<span class="token comment">-- 列出 meeting 表中的 pic_url，</span>
<span class="token comment">-- station 表中的 number_station 别名设置成 pic_url 避免字段不一样报错</span>
<span class="token comment">-- 按更新时间排序</span>
<span class="token keyword">SELECT</span> id<span class="token punctuation">,</span>pic_url <span class="token keyword">FROM</span> meeting <span class="token keyword">UNION</span> <span class="token keyword">ALL</span> <span class="token keyword">SELECT</span> id<span class="token punctuation">,</span>number_station <span class="token keyword">AS</span> pic_url <span class="token keyword">FROM</span> station  <span class="token keyword">ORDER</span> <span class="token keyword">BY</span> update_at<span class="token punctuation">;</span>
<span class="token comment">-- 通过 UNION 语法同时查询了 products 表 和 comments 表的总记录数，并且按照 count 排序</span>
<span class="token keyword">SELECT</span> <span class="token string">&#39;product&#39;</span> <span class="token keyword">AS</span> <span class="token keyword">type</span><span class="token punctuation">,</span> <span class="token function">count</span><span class="token punctuation">(</span><span class="token operator">*</span><span class="token punctuation">)</span> <span class="token keyword">as</span> count <span class="token keyword">FROM</span> <span class="token identifier"><span class="token punctuation">\`</span>products<span class="token punctuation">\`</span></span> <span class="token keyword">union</span> <span class="token keyword">select</span> <span class="token string">&#39;comment&#39;</span> <span class="token keyword">as</span> <span class="token keyword">type</span><span class="token punctuation">,</span> <span class="token function">count</span><span class="token punctuation">(</span><span class="token operator">*</span><span class="token punctuation">)</span> <span class="token keyword">as</span> count <span class="token keyword">FROM</span> <span class="token identifier"><span class="token punctuation">\`</span>comments<span class="token punctuation">\`</span></span> <span class="token keyword">order</span> <span class="token keyword">by</span> count<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="between" tabindex="-1"><a class="header-anchor" href="#between" aria-hidden="true">#</a> BETWEEN</h2><blockquote><p><code>BETWEEN 语法</code> 运算符选择给定范围内的值</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> 列名称<span class="token punctuation">(</span>s<span class="token punctuation">)</span> <span class="token keyword">FROM</span> 表名称 <span class="token keyword">WHERE</span> 列名称 <span class="token operator">BETWEEN</span> 值<span class="token number">1</span> <span class="token operator">AND</span> 值<span class="token number">2</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 选择 Products 表中 Price 字段在 10 到 20 之间的所有：</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Products <span class="token keyword">WHERE</span> Price <span class="token operator">BETWEEN</span> <span class="token number">10</span> <span class="token operator">AND</span> <span class="token number">20</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="as" tabindex="-1"><a class="header-anchor" href="#as" aria-hidden="true">#</a> AS</h2><blockquote><p><code>AS 语法</code> 用于为表或表中的列(字段)提供临时名称(别名)。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> 列名称 <span class="token keyword">AS</span> 别名 <span class="token keyword">FROM</span> 表名称<span class="token punctuation">;</span>
<span class="token keyword">SELECT</span> 列名称<span class="token punctuation">(</span>s<span class="token punctuation">)</span> <span class="token keyword">FROM</span> 表名称 <span class="token keyword">AS</span> 别名<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 创建两个别名，一个用于 CustomerID 的 ID 别名列，一个用于 CustomerName  的 Customer 别名列：</span>
<span class="token keyword">SELECT</span> CustomerID <span class="token keyword">AS</span> ID<span class="token punctuation">,</span> CustomerName <span class="token keyword">AS</span> Customer <span class="token keyword">FROM</span> Customers<span class="token punctuation">;</span>

<span class="token comment">-- 这句意思是查找所有 Employee 表里面的数据，并把 Employee 表格命名为 emp。</span>
<span class="token comment">-- 当你命名一个表之后，你可以在下面用 emp 代替 Employee.</span>
<span class="token comment">-- 例如 SELECT * FROM emp.</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> Employee <span class="token keyword">AS</span> emp

<span class="token comment">-- 列出表 Orders 字段 OrderPrice 列最大值，</span>
<span class="token comment">-- 结果集列不显示 OrderPrice 显示 LargestOrderPrice</span>
<span class="token keyword">SELECT</span> <span class="token function">MAX</span><span class="token punctuation">(</span>OrderPrice<span class="token punctuation">)</span> <span class="token keyword">AS</span> LargestOrderPrice <span class="token keyword">FROM</span> Orders

<span class="token comment">-- 显示表 users_profile 中的 name 列</span>
<span class="token keyword">SELECT</span> t<span class="token punctuation">.</span>name <span class="token keyword">from</span> <span class="token punctuation">(</span><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">from</span> users_profile a<span class="token punctuation">)</span> <span class="token keyword">AS</span> t<span class="token punctuation">;</span>

<span class="token comment">-- 表 user_accounts 命名别名 ua，表 users_profile 命名别名 up</span>
<span class="token comment">-- 满足条件 表 user_accounts 字段 id 等于 表 users_profile 字段 user_id</span>
<span class="token comment">-- 结果集只显示mobile、name两列</span>
<span class="token keyword">SELECT</span> ua<span class="token punctuation">.</span>mobile<span class="token punctuation">,</span>up<span class="token punctuation">.</span>name <span class="token keyword">FROM</span> user_accounts <span class="token keyword">as</span> ua <span class="token keyword">INNER</span> <span class="token keyword">JOIN</span> users_profile <span class="token keyword">as</span> up <span class="token keyword">ON</span> ua<span class="token punctuation">.</span>id <span class="token operator">=</span> up<span class="token punctuation">.</span>user_id<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="join" tabindex="-1"><a class="header-anchor" href="#join" aria-hidden="true">#</a> JOIN</h2><p>JOIN 子句用于根据两个或多个表之间的相关列组合来自两个或多个表的行。</p><ul><li><code>JOIN</code>: 如果表中有至少一个匹配，则返回行</li><li><code>INNER JOIN</code>:在表中存在至少一个匹配时，INNER JOIN 关键字返回行。</li><li><code>LEFT JOIN</code>: 即使右表中没有匹配，也从左表返回所有的行</li><li><code>RIGHT JOIN</code>: 即使左表中没有匹配，也从右表返回所有的行</li><li><code>FULL JOIN</code>: 只要其中一个表中存在匹配，就返回行(MySQL 是不支持的，通过 <code>LEFT JOIN + UNION + RIGHT JOIN</code> 的方式 来实现)</li></ul><h3 id="inner-join" tabindex="-1"><a class="header-anchor" href="#inner-join" aria-hidden="true">#</a> INNER JOIN</h3><blockquote><p><code>INNER JOIN 语法</code> 选择在两个表中具有匹配值的记录。</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> 列名称<span class="token punctuation">(</span>s<span class="token punctuation">)</span>
<span class="token keyword">FROM</span> 表<span class="token number">1</span>
<span class="token keyword">INNER</span> <span class="token keyword">JOIN</span> 表<span class="token number">2</span>
<span class="token keyword">ON</span> 表<span class="token number">1.</span>列名称 <span class="token operator">=</span> 表<span class="token number">2.</span>列名称<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 选择包含 Customers 的所有 Orders：</span>
<span class="token keyword">SELECT</span> Orders<span class="token punctuation">.</span>OrderID<span class="token punctuation">,</span> Customers<span class="token punctuation">.</span>CustomerName <span class="token keyword">FROM</span> Orders <span class="token keyword">INNER</span> <span class="token keyword">JOIN</span> Customers <span class="token keyword">ON</span> Orders<span class="token punctuation">.</span>CustomerID <span class="token operator">=</span> Customers<span class="token punctuation">.</span>CustomerID<span class="token punctuation">;</span>

<span class="token comment">-- [JOIN 三张表] 选择包含 Customers 和 Shippers 的所有 Orders：</span>
<span class="token keyword">SELECT</span> Orders<span class="token punctuation">.</span>OrderID<span class="token punctuation">,</span> Customers<span class="token punctuation">.</span>CustomerName<span class="token punctuation">,</span> Shippers<span class="token punctuation">.</span>ShipperName
<span class="token keyword">FROM</span> <span class="token punctuation">(</span><span class="token punctuation">(</span>Orders
<span class="token keyword">INNER</span> <span class="token keyword">JOIN</span> Customers <span class="token keyword">ON</span> Orders<span class="token punctuation">.</span>CustomerID <span class="token operator">=</span> Customers<span class="token punctuation">.</span>CustomerID<span class="token punctuation">)</span>
<span class="token keyword">INNER</span> <span class="token keyword">JOIN</span> Shippers <span class="token keyword">ON</span> Orders<span class="token punctuation">.</span>ShipperID <span class="token operator">=</span> Shippers<span class="token punctuation">.</span>ShipperID<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="left-join" tabindex="-1"><a class="header-anchor" href="#left-join" aria-hidden="true">#</a> LEFT JOIN</h3><blockquote><p><code>LEFT JOIN 语法</code> 返回左表 (表1) 中的所有记录，以及右表 (表2) 中的匹配记录</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> 列名称<span class="token punctuation">(</span>s<span class="token punctuation">)</span>
<span class="token keyword">FROM</span> 表<span class="token number">1</span>
<span class="token keyword">LEFT</span> <span class="token keyword">JOIN</span> 表<span class="token number">2</span>
<span class="token keyword">ON</span> 表<span class="token number">1.</span>列名称 <span class="token operator">=</span> 表<span class="token number">2.</span>列名称<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 将选择所有 Customers 以及他们可能拥有的任何 Orders：</span>
<span class="token keyword">SELECT</span> Customers<span class="token punctuation">.</span>CustomerName<span class="token punctuation">,</span> Orders<span class="token punctuation">.</span>OrderID <span class="token keyword">FROM</span> Customers
<span class="token keyword">LEFT</span> <span class="token keyword">JOIN</span> Orders <span class="token keyword">ON</span> Customers<span class="token punctuation">.</span>CustomerID <span class="token operator">=</span> Orders<span class="token punctuation">.</span>CustomerID
<span class="token keyword">ORDER</span> <span class="token keyword">BY</span> Customers<span class="token punctuation">.</span>CustomerName<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="right-join" tabindex="-1"><a class="header-anchor" href="#right-join" aria-hidden="true">#</a> RIGHT JOIN</h3><blockquote><p><code>RIGHT JOIN 语法</code> 返回右表 (表2) 中的所有记录，以及左表 (表1) 中的匹配记录</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> 列名称<span class="token punctuation">(</span>s<span class="token punctuation">)</span>
<span class="token keyword">FROM</span> 表<span class="token number">1</span>
<span class="token keyword">RIGHT</span> <span class="token keyword">JOIN</span> 表<span class="token number">2</span>
<span class="token keyword">ON</span> 表<span class="token number">1.</span>列名称 <span class="token operator">=</span> 表<span class="token number">2.</span>列名称<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 返回所有 Employees 以及他们可能下的任何 Orders：</span>
<span class="token keyword">SELECT</span> Orders<span class="token punctuation">.</span>OrderID<span class="token punctuation">,</span> Employees<span class="token punctuation">.</span>LastName<span class="token punctuation">,</span> Employees<span class="token punctuation">.</span>FirstName <span class="token keyword">FROM</span> Orders
<span class="token keyword">RIGHT</span> <span class="token keyword">JOIN</span> Employees <span class="token keyword">ON</span> Orders<span class="token punctuation">.</span>EmployeeID <span class="token operator">=</span> Employees<span class="token punctuation">.</span>EmployeeID
<span class="token keyword">ORDER</span> <span class="token keyword">BY</span> Orders<span class="token punctuation">.</span>OrderID<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="full-outer-join" tabindex="-1"><a class="header-anchor" href="#full-outer-join" aria-hidden="true">#</a> FULL OUTER JOIN</h3><blockquote><p><code>FULL OUTER JOIN 语法</code> 当左（表1）或右（表2）表记录中存在匹配时，关键字返回所有记录</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> 列名称<span class="token punctuation">(</span>s<span class="token punctuation">)</span>
<span class="token keyword">FROM</span> 表<span class="token number">1</span>
<span class="token keyword">FULL</span> <span class="token keyword">OUTER</span> <span class="token keyword">JOIN</span> 表<span class="token number">2</span>
<span class="token keyword">ON</span> 表<span class="token number">1.</span>列名称 <span class="token operator">=</span> 表<span class="token number">2.</span>列名称
<span class="token keyword">WHERE</span> 条件<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><h2 id="sql-函数" tabindex="-1"><a class="header-anchor" href="#sql-函数" aria-hidden="true">#</a> SQL 函数</h2><h3 id="count" tabindex="-1"><a class="header-anchor" href="#count" aria-hidden="true">#</a> COUNT</h3><blockquote><p><code>COUNT 语法</code> 返回与指定条件匹配的行数</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token function">COUNT</span><span class="token punctuation">(</span>列名称<span class="token punctuation">)</span> <span class="token keyword">FROM</span> 表名称 <span class="token keyword">WHERE</span> 条件<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 表 Store_Information 有几笔 store_name 栏不是空白的资料。</span>
<span class="token comment">-- &quot;IS NOT NULL&quot; 是 &quot;这个栏位不是空白&quot; 的意思。</span>
<span class="token keyword">SELECT</span> <span class="token function">COUNT</span> <span class="token punctuation">(</span>Store_Name<span class="token punctuation">)</span> <span class="token keyword">FROM</span> Store_Information <span class="token keyword">WHERE</span> Store_Name <span class="token operator">IS</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span><span class="token punctuation">;</span> 
<span class="token comment">-- 获取 Persons 表的总数</span>
<span class="token keyword">SELECT</span> <span class="token function">COUNT</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span> <span class="token keyword">AS</span> totals <span class="token keyword">FROM</span> Persons<span class="token punctuation">;</span>
<span class="token comment">-- 获取表 station 字段 user_id 相同的总数</span>
<span class="token keyword">select</span> user_id<span class="token punctuation">,</span> <span class="token function">count</span><span class="token punctuation">(</span><span class="token operator">*</span><span class="token punctuation">)</span> <span class="token keyword">as</span> totals <span class="token keyword">from</span> station <span class="token keyword">group</span> <span class="token keyword">by</span> user_id<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="avg" tabindex="-1"><a class="header-anchor" href="#avg" aria-hidden="true">#</a> AVG</h3><blockquote><p><code>AVG 语法</code> 返回数值列的平均值</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token function">AVG</span><span class="token punctuation">(</span>列名称<span class="token punctuation">)</span> <span class="token keyword">FROM</span> 表名称 <span class="token keyword">WHERE</span> 条件<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 查找 Products 表中所的 Price 平均值：</span>
<span class="token keyword">SELECT</span> <span class="token function">AVG</span><span class="token punctuation">(</span>Price<span class="token punctuation">)</span> <span class="token keyword">FROM</span> Products<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="sum" tabindex="-1"><a class="header-anchor" href="#sum" aria-hidden="true">#</a> SUM</h3><blockquote><p><code>SUM 语法</code> 返回数值列的总和</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token function">SUM</span><span class="token punctuation">(</span>列名称<span class="token punctuation">)</span> <span class="token keyword">FROM</span> 表名称 <span class="token keyword">WHERE</span> 条件<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 查找 OrderDetails 表中 Quantity 字段的总和：</span>
<span class="token keyword">SELECT</span> <span class="token function">SUM</span><span class="token punctuation">(</span>Quantity<span class="token punctuation">)</span> <span class="token keyword">FROM</span> OrderDetails<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="max" tabindex="-1"><a class="header-anchor" href="#max" aria-hidden="true">#</a> MAX</h3><blockquote><p><code>MAX 语法</code> 返回所选列的最大值</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token function">MIN</span><span class="token punctuation">(</span>列名称<span class="token punctuation">)</span> <span class="token keyword">FROM</span> 表名称 <span class="token keyword">WHERE</span> 条件<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 列出表 Orders 字段 OrderPrice 列最大值，</span>
<span class="token comment">-- 结果集列不显示 OrderPrice 显示 LargestOrderPrice</span>
<span class="token keyword">SELECT</span> <span class="token function">MAX</span><span class="token punctuation">(</span>OrderPrice<span class="token punctuation">)</span> <span class="token keyword">AS</span> LargestOrderPrice <span class="token keyword">FROM</span> Orders
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="min" tabindex="-1"><a class="header-anchor" href="#min" aria-hidden="true">#</a> MIN</h3><blockquote><p><code>MIN 语法</code> 返回所选列的最小值</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token function">MIN</span><span class="token punctuation">(</span>列名称<span class="token punctuation">)</span> <span class="token keyword">FROM</span> 表名称 <span class="token keyword">WHERE</span> 条件<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 查找 Products 表中 Price 字段最小值，并命名 SmallestPrice 别名：</span>
<span class="token keyword">SELECT</span> <span class="token function">MIN</span><span class="token punctuation">(</span>Price<span class="token punctuation">)</span> <span class="token keyword">AS</span> SmallestPrice <span class="token keyword">FROM</span> Products<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="触发器" tabindex="-1"><a class="header-anchor" href="#触发器" aria-hidden="true">#</a> 触发器</h2><blockquote><p>语法：</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">create</span> <span class="token keyword">trigger</span> <span class="token operator">&lt;</span>触发器名称<span class="token operator">&gt;</span>  
{ before <span class="token operator">|</span> <span class="token keyword">after</span>}         <span class="token comment">-- 之前或者之后出发  </span>
<span class="token keyword">insert</span> <span class="token operator">|</span> <span class="token keyword">update</span> <span class="token operator">|</span> <span class="token keyword">delete</span>  <span class="token comment">-- 指明了激活触发程序的语句的类型  </span>
<span class="token keyword">on</span> <span class="token operator">&lt;</span>表名<span class="token operator">&gt;</span>                  <span class="token comment">-- 操作哪张表  </span>
<span class="token keyword">for each row</span>              <span class="token comment">-- 触发器的执行间隔，for each row 通知触发器每隔一行执行一次动作，而不是对整个表执行一次。  </span>
<span class="token operator">&lt;</span>触发器<span class="token keyword">SQL</span>语句<span class="token operator">&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">delimiter</span> $
<span class="token keyword">CREATE</span> <span class="token keyword">TRIGGER</span> set_userdate BEFORE <span class="token keyword">INSERT</span> 
<span class="token keyword">on</span> <span class="token identifier"><span class="token punctuation">\`</span>message<span class="token punctuation">\`</span></span>
<span class="token keyword">for EACH ROW</span>
<span class="token keyword">BEGIN</span>
  <span class="token keyword">set</span> <span class="token variable">@statu</span> <span class="token operator">=</span> new<span class="token punctuation">.</span><span class="token keyword">status</span><span class="token punctuation">;</span> <span class="token comment">-- 声明复制变量 statu</span>
  <span class="token keyword">if</span> <span class="token variable">@statu</span> <span class="token operator">=</span> <span class="token number">0</span> <span class="token keyword">then</span>       <span class="token comment">-- 判断 statu 是否等于 0</span>
    <span class="token keyword">UPDATE</span> <span class="token identifier"><span class="token punctuation">\`</span>user_accounts<span class="token punctuation">\`</span></span> <span class="token keyword">SET</span> <span class="token keyword">status</span><span class="token operator">=</span><span class="token number">1</span> <span class="token keyword">WHERE</span> openid<span class="token operator">=</span>NEW<span class="token punctuation">.</span>openid<span class="token punctuation">;</span>
  <span class="token keyword">end</span> <span class="token keyword">if</span><span class="token punctuation">;</span>
<span class="token keyword">END</span>
$
<span class="token keyword">DELIMITER</span> <span class="token punctuation">;</span> <span class="token comment">-- 恢复结束符号</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>OLD和NEW不区分大小写</p><ul><li>NEW 用NEW.col_name，没有旧行。在DELETE触发程序中，仅能使用OLD.col_name，没有新行。</li><li>OLD 用OLD.col_name来引用更新前的某一行的列</li></ul><h2 id="添加索引" tabindex="-1"><a class="header-anchor" href="#添加索引" aria-hidden="true">#</a> 添加索引</h2><h3 id="普通索引-index" tabindex="-1"><a class="header-anchor" href="#普通索引-index" aria-hidden="true">#</a> 普通索引(INDEX)</h3><blockquote><p>语法：ALTER TABLE <code>表名字</code> ADD INDEX 索引名字 ( <code>字段名字</code> )</p></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- –直接创建索引</span>
<span class="token keyword">CREATE</span> <span class="token keyword">INDEX</span> index_user <span class="token keyword">ON</span> <span class="token keyword">user</span><span class="token punctuation">(</span>title<span class="token punctuation">)</span>
<span class="token comment">-- –修改表结构的方式添加索引</span>
<span class="token keyword">ALTER</span> <span class="token keyword">TABLE</span> table_name <span class="token keyword">ADD</span> <span class="token keyword">INDEX</span> index_name <span class="token keyword">ON</span> <span class="token punctuation">(</span><span class="token keyword">column</span><span class="token punctuation">(</span>length<span class="token punctuation">)</span><span class="token punctuation">)</span>
<span class="token comment">-- 给 user 表中的 name 字段 添加普通索引(INDEX)</span>
<span class="token keyword">ALTER</span> <span class="token keyword">TABLE</span> <span class="token identifier"><span class="token punctuation">\`</span>user<span class="token punctuation">\`</span></span> <span class="token keyword">ADD</span> <span class="token keyword">INDEX</span> index_name <span class="token punctuation">(</span>name<span class="token punctuation">)</span>
<span class="token comment">-- –创建表的时候同时创建索引</span>
<span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> <span class="token identifier"><span class="token punctuation">\`</span>user<span class="token punctuation">\`</span></span> <span class="token punctuation">(</span>
    <span class="token identifier"><span class="token punctuation">\`</span>id<span class="token punctuation">\`</span></span> <span class="token keyword">int</span><span class="token punctuation">(</span><span class="token number">11</span><span class="token punctuation">)</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token keyword">AUTO_INCREMENT</span> <span class="token punctuation">,</span>
    <span class="token identifier"><span class="token punctuation">\`</span>title<span class="token punctuation">\`</span></span> <span class="token keyword">char</span><span class="token punctuation">(</span><span class="token number">255</span><span class="token punctuation">)</span> <span class="token keyword">CHARACTER</span> <span class="token keyword">SET</span> utf8 <span class="token keyword">COLLATE</span> utf8_general_ci <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token punctuation">,</span>
    <span class="token identifier"><span class="token punctuation">\`</span>content<span class="token punctuation">\`</span></span> <span class="token keyword">text</span> <span class="token keyword">CHARACTER</span> <span class="token keyword">SET</span> utf8 <span class="token keyword">COLLATE</span> utf8_general_ci <span class="token boolean">NULL</span> <span class="token punctuation">,</span>
    <span class="token identifier"><span class="token punctuation">\`</span>time<span class="token punctuation">\`</span></span> <span class="token keyword">int</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span> <span class="token boolean">NULL</span> <span class="token keyword">DEFAULT</span> <span class="token boolean">NULL</span> <span class="token punctuation">,</span>
    <span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span> <span class="token punctuation">(</span><span class="token identifier"><span class="token punctuation">\`</span>id<span class="token punctuation">\`</span></span><span class="token punctuation">)</span><span class="token punctuation">,</span>
    <span class="token keyword">INDEX</span> index_name <span class="token punctuation">(</span>title<span class="token punctuation">(</span>length<span class="token punctuation">)</span><span class="token punctuation">)</span>
<span class="token punctuation">)</span>
<span class="token comment">-- –删除索引</span>
<span class="token keyword">DROP</span> <span class="token keyword">INDEX</span> index_name <span class="token keyword">ON</span> <span class="token keyword">table</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="主键索引-primary-key" tabindex="-1"><a class="header-anchor" href="#主键索引-primary-key" aria-hidden="true">#</a> 主键索引(PRIMARY key)</h3><blockquote><p>语法：ALTER TABLE <code>表名字</code> ADD PRIMARY KEY ( <code>字段名字</code> )</p></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 给 user 表中的 id字段 添加主键索引(PRIMARY key)</span>
<span class="token keyword">ALTER</span> <span class="token keyword">TABLE</span> <span class="token identifier"><span class="token punctuation">\`</span>user<span class="token punctuation">\`</span></span> <span class="token keyword">ADD</span> <span class="token keyword">PRIMARY</span> <span class="token keyword">key</span> <span class="token punctuation">(</span>id<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="唯一索引-unique" tabindex="-1"><a class="header-anchor" href="#唯一索引-unique" aria-hidden="true">#</a> 唯一索引(UNIQUE)</h3><blockquote><p>语法：ALTER TABLE <code>表名字</code> ADD UNIQUE (<code>字段名字</code>)</p></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 给 user 表中的 creattime 字段添加唯一索引(UNIQUE)</span>
<span class="token keyword">ALTER</span> <span class="token keyword">TABLE</span> <span class="token identifier"><span class="token punctuation">\`</span>user<span class="token punctuation">\`</span></span> <span class="token keyword">ADD</span> <span class="token keyword">UNIQUE</span> <span class="token punctuation">(</span>creattime<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="全文索引-fulltext" tabindex="-1"><a class="header-anchor" href="#全文索引-fulltext" aria-hidden="true">#</a> 全文索引(FULLTEXT)</h3><blockquote><p>语法：ALTER TABLE <code>表名字</code> ADD FULLTEXT (<code>字段名字</code>)</p></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 给 user 表中的 description 字段添加全文索引(FULLTEXT)</span>
<span class="token keyword">ALTER</span> <span class="token keyword">TABLE</span> <span class="token identifier"><span class="token punctuation">\`</span>user<span class="token punctuation">\`</span></span> <span class="token keyword">ADD</span> FULLTEXT <span class="token punctuation">(</span>description<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="添加多列索引" tabindex="-1"><a class="header-anchor" href="#添加多列索引" aria-hidden="true">#</a> 添加多列索引</h3><blockquote><p>语法： ALTER TABLE <code>table_name</code> ADD INDEX index_name ( <code>column1</code>, <code>column2</code>, <code>column3</code>)</p></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 给 user 表中的 name、city、age 字段添加名字为name_city_age的普通索引(INDEX)</span>
<span class="token keyword">ALTER</span> <span class="token keyword">TABLE</span> <span class="token keyword">user</span> <span class="token keyword">ADD</span> <span class="token keyword">INDEX</span> name_city_age <span class="token punctuation">(</span>name<span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">,</span>city<span class="token punctuation">,</span>age<span class="token punctuation">)</span><span class="token punctuation">;</span> 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="建立索引的时机" tabindex="-1"><a class="header-anchor" href="#建立索引的时机" aria-hidden="true">#</a> 建立索引的时机</h3><p>在<code>WHERE</code>和<code>JOIN</code>中出现的列需要建立索引，但也不完全如此：</p><ul><li>MySQL只对<code>&lt;</code>，<code>&lt;=</code>，<code>=</code>，<code>&gt;</code>，<code>&gt;=</code>，<code>BETWEEN</code>，<code>IN</code>使用索引</li><li>某些时候的<code>LIKE</code>也会使用索引。</li><li>在<code>LIKE</code>以通配符%和_开头作查询时，MySQL不会使用索引。</li></ul><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 此时就需要对city和age建立索引，</span>
<span class="token comment">-- 由于mytable表的userame也出现在了JOIN子句中，也有对它建立索引的必要。</span>
<span class="token keyword">SELECT</span> t<span class="token punctuation">.</span>Name  
<span class="token keyword">FROM</span> mytable t <span class="token keyword">LEFT</span> <span class="token keyword">JOIN</span> mytable m <span class="token keyword">ON</span> t<span class="token punctuation">.</span>Name<span class="token operator">=</span>m<span class="token punctuation">.</span>username 
<span class="token keyword">WHERE</span> m<span class="token punctuation">.</span>age<span class="token operator">=</span><span class="token number">20</span> <span class="token operator">AND</span> m<span class="token punctuation">.</span>city<span class="token operator">=</span><span class="token string">&#39;上海&#39;</span><span class="token punctuation">;</span>

<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> mytable <span class="token keyword">WHERE</span> username <span class="token operator">like</span><span class="token string">&#39;admin%&#39;</span><span class="token punctuation">;</span> <span class="token comment">-- 而下句就不会使用：</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> mytable <span class="token keyword">WHERE</span> Name <span class="token operator">like</span><span class="token string">&#39;%admin&#39;</span><span class="token punctuation">;</span> <span class="token comment">-- 因此，在使用LIKE时应注意以上的区别。</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>索引的注意事项</p><ul><li>索引不会包含有NULL值的列</li><li>使用短索引</li><li>不要在列上进行运算 索引会失效</li></ul><h2 id="创建后表的修改" tabindex="-1"><a class="header-anchor" href="#创建后表的修改" aria-hidden="true">#</a> 创建后表的修改</h2><h3 id="添加列" tabindex="-1"><a class="header-anchor" href="#添加列" aria-hidden="true">#</a> 添加列</h3><blockquote><p>语法：<code>alter table 表名 add 列名 列数据类型 [after 插入位置];</code></p></blockquote><p>示例:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 在表students的最后追加列 address: </span>
<span class="token keyword">alter</span> <span class="token keyword">table</span> students <span class="token keyword">add</span> address <span class="token keyword">char</span><span class="token punctuation">(</span><span class="token number">60</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">-- 在名为 age 的列后插入列 birthday: </span>
<span class="token keyword">alter</span> <span class="token keyword">table</span> students <span class="token keyword">add</span> birthday <span class="token keyword">date</span> <span class="token keyword">after</span> age<span class="token punctuation">;</span>
<span class="token comment">-- 在名为 number_people 的列后插入列 weeks: </span>
<span class="token keyword">alter</span> <span class="token keyword">table</span> students <span class="token keyword">add</span> <span class="token keyword">column</span> <span class="token identifier"><span class="token punctuation">\`</span>weeks<span class="token punctuation">\`</span></span> <span class="token keyword">varchar</span><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">)</span> <span class="token operator">not</span> <span class="token boolean">null</span> <span class="token keyword">default</span> <span class="token string">&quot;&quot;</span> <span class="token keyword">after</span> <span class="token identifier"><span class="token punctuation">\`</span>number_people<span class="token punctuation">\`</span></span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="修改列" tabindex="-1"><a class="header-anchor" href="#修改列" aria-hidden="true">#</a> 修改列</h3><blockquote><p>语法：<code>alter table 表名 change 列名称 列新名称 新数据类型;</code></p></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 将表 tel 列改名为 telphone: </span>
<span class="token keyword">alter</span> <span class="token keyword">table</span> students change tel telphone <span class="token keyword">char</span><span class="token punctuation">(</span><span class="token number">13</span><span class="token punctuation">)</span> <span class="token keyword">default</span> <span class="token string">&quot;-&quot;</span><span class="token punctuation">;</span>
<span class="token comment">-- 将 name 列的数据类型改为 char(16): </span>
<span class="token keyword">alter</span> <span class="token keyword">table</span> students change name name <span class="token keyword">char</span><span class="token punctuation">(</span><span class="token number">16</span><span class="token punctuation">)</span> <span class="token operator">not</span> <span class="token boolean">null</span><span class="token punctuation">;</span>
<span class="token comment">-- 修改 COMMENT 前面必须得有类型属性</span>
<span class="token keyword">alter</span> <span class="token keyword">table</span> students change name name <span class="token keyword">char</span><span class="token punctuation">(</span><span class="token number">16</span><span class="token punctuation">)</span> <span class="token keyword">COMMENT</span> <span class="token string">&#39;这里是名字&#39;</span><span class="token punctuation">;</span>
<span class="token comment">-- 修改列属性的时候 建议使用modify,不需要重建表</span>
<span class="token comment">-- change用于修改列名字，这个需要重建表</span>
<span class="token keyword">alter</span> <span class="token keyword">table</span> meeting <span class="token keyword">modify</span> <span class="token identifier"><span class="token punctuation">\`</span>weeks<span class="token punctuation">\`</span></span> <span class="token keyword">varchar</span><span class="token punctuation">(</span><span class="token number">20</span><span class="token punctuation">)</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token keyword">DEFAULT</span> <span class="token string">&#39;&#39;</span> <span class="token keyword">COMMENT</span> <span class="token string">&#39;开放日期 周一到周日：0~6，间隔用英文逗号隔开&#39;</span><span class="token punctuation">;</span>
<span class="token comment">-- \`user\`表的\`id\`列，修改成字符串类型长度50，不能为空，\`FIRST\`放在第一列的位置</span>
<span class="token keyword">alter</span> <span class="token keyword">table</span> <span class="token identifier"><span class="token punctuation">\`</span>user<span class="token punctuation">\`</span></span> <span class="token keyword">modify</span> <span class="token keyword">COLUMN</span> <span class="token identifier"><span class="token punctuation">\`</span>id<span class="token punctuation">\`</span></span> <span class="token keyword">varchar</span><span class="token punctuation">(</span><span class="token number">50</span><span class="token punctuation">)</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token keyword">FIRST</span> <span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="删除列" tabindex="-1"><a class="header-anchor" href="#删除列" aria-hidden="true">#</a> 删除列</h3><blockquote><p>语法：<code>alter table 表名 drop 列名称;</code></p></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 删除表students中的 birthday 列: </span>
<span class="token keyword">alter</span> <span class="token keyword">table</span> students <span class="token keyword">drop</span> birthday<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="重命名表" tabindex="-1"><a class="header-anchor" href="#重命名表" aria-hidden="true">#</a> 重命名表</h3><blockquote><p>语法：<code>alter table 表名 rename 新表名;</code></p></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 重命名 students 表为 workmates: </span>
<span class="token keyword">alter</span> <span class="token keyword">table</span> students <span class="token keyword">rename</span> workmates<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="清空表数据" tabindex="-1"><a class="header-anchor" href="#清空表数据" aria-hidden="true">#</a> 清空表数据</h3><blockquote><p>方法一：<code>delete from 表名;</code> 方法二：<code>truncate table &quot;表名&quot;;</code></p></blockquote><ul><li><code>DELETE:</code>1. DML语言;2. 可以回退;3. 可以有条件的删除;</li><li><code>TRUNCATE:</code>1. DDL语言;2. 无法回退;3. 默认所有的表内容都删除;4. 删除速度比delete快。</li></ul><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 清空表为 workmates 里面的数据，不删除表。 </span>
<span class="token keyword">delete</span> <span class="token keyword">from</span> workmates<span class="token punctuation">;</span>
<span class="token comment">-- 删除workmates表中的所有数据，且无法恢复</span>
<span class="token keyword">truncate</span> <span class="token keyword">table</span> workmates<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="删除整张表" tabindex="-1"><a class="header-anchor" href="#删除整张表" aria-hidden="true">#</a> 删除整张表</h3><blockquote><p>语法：<code>drop table 表名;</code></p></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 删除 workmates 表: </span>
<span class="token keyword">drop</span> <span class="token keyword">table</span> workmates<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="删除整个数据库" tabindex="-1"><a class="header-anchor" href="#删除整个数据库" aria-hidden="true">#</a> 删除整个数据库</h3><blockquote><p>语法：<code>drop database 数据库名;</code></p></blockquote><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 删除 samp_db 数据库: </span>
<span class="token keyword">drop</span> <span class="token keyword">database</span> samp_db<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="其它实例" tabindex="-1"><a class="header-anchor" href="#其它实例" aria-hidden="true">#</a> 其它实例</h2><h3 id="sql删除重复记录" tabindex="-1"><a class="header-anchor" href="#sql删除重复记录" aria-hidden="true">#</a> SQL删除重复记录</h3>`,151),y={href:"http://www.xiangguo.li/sql_and_nosql/2015/01/01/sql",target:"_blank",rel:"noopener noreferrer"},E=e(`<div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 查找表中多余的重复记录，重复记录是根据单个字段（peopleId）来判断</span>
<span class="token keyword">select</span> <span class="token operator">*</span> <span class="token keyword">from</span> people <span class="token keyword">where</span> peopleId <span class="token operator">in</span> <span class="token punctuation">(</span><span class="token keyword">select</span> peopleId <span class="token keyword">from</span> people <span class="token keyword">group</span> <span class="token keyword">by</span> peopleId <span class="token keyword">having</span> <span class="token function">count</span><span class="token punctuation">(</span>peopleId<span class="token punctuation">)</span> <span class="token operator">&gt;</span> <span class="token number">1</span><span class="token punctuation">)</span>
<span class="token comment">-- 删除表中多余的重复记录，重复记录是根据单个字段（peopleId）来判断，只留有rowid最小的记录</span>
<span class="token keyword">delete</span> <span class="token keyword">from</span> people 
<span class="token keyword">where</span> peopleId <span class="token operator">in</span> <span class="token punctuation">(</span><span class="token keyword">select</span> peopleId <span class="token keyword">from</span> people <span class="token keyword">group</span> <span class="token keyword">by</span> peopleId <span class="token keyword">having</span> <span class="token function">count</span><span class="token punctuation">(</span>peopleId<span class="token punctuation">)</span> <span class="token operator">&gt;</span> <span class="token number">1</span><span class="token punctuation">)</span>
<span class="token operator">and</span> rowid <span class="token operator">not</span> <span class="token operator">in</span> <span class="token punctuation">(</span><span class="token keyword">select</span> <span class="token function">min</span><span class="token punctuation">(</span>rowid<span class="token punctuation">)</span> <span class="token keyword">from</span> people <span class="token keyword">group</span> <span class="token keyword">by</span> peopleId <span class="token keyword">having</span> <span class="token function">count</span><span class="token punctuation">(</span>peopleId <span class="token punctuation">)</span><span class="token operator">&gt;</span><span class="token number">1</span><span class="token punctuation">)</span>
<span class="token comment">-- 查找表中多余的重复记录（多个字段）</span>
<span class="token keyword">select</span> <span class="token operator">*</span> <span class="token keyword">from</span> vitae a
<span class="token keyword">where</span> <span class="token punctuation">(</span>a<span class="token punctuation">.</span>peopleId<span class="token punctuation">,</span>a<span class="token punctuation">.</span>seq<span class="token punctuation">)</span> <span class="token operator">in</span> <span class="token punctuation">(</span><span class="token keyword">select</span> peopleId<span class="token punctuation">,</span>seq <span class="token keyword">from</span> vitae <span class="token keyword">group</span> <span class="token keyword">by</span> peopleId<span class="token punctuation">,</span>seq <span class="token keyword">having</span> <span class="token function">count</span><span class="token punctuation">(</span><span class="token operator">*</span><span class="token punctuation">)</span> <span class="token operator">&gt;</span> <span class="token number">1</span><span class="token punctuation">)</span>
<span class="token comment">-- 删除表中多余的重复记录（多个字段），只留有rowid最小的记录</span>
<span class="token keyword">delete</span> <span class="token keyword">from</span> vitae a
<span class="token keyword">where</span> <span class="token punctuation">(</span>a<span class="token punctuation">.</span>peopleId<span class="token punctuation">,</span>a<span class="token punctuation">.</span>seq<span class="token punctuation">)</span> <span class="token operator">in</span> <span class="token punctuation">(</span><span class="token keyword">select</span> peopleId<span class="token punctuation">,</span>seq <span class="token keyword">from</span> vitae <span class="token keyword">group</span> <span class="token keyword">by</span> peopleId<span class="token punctuation">,</span>seq <span class="token keyword">having</span> <span class="token function">count</span><span class="token punctuation">(</span><span class="token operator">*</span><span class="token punctuation">)</span> <span class="token operator">&gt;</span> <span class="token number">1</span><span class="token punctuation">)</span> <span class="token operator">and</span> rowid <span class="token operator">not</span> <span class="token operator">in</span> <span class="token punctuation">(</span><span class="token keyword">select</span> <span class="token function">min</span><span class="token punctuation">(</span>rowid<span class="token punctuation">)</span> <span class="token keyword">from</span> vitae <span class="token keyword">group</span> <span class="token keyword">by</span> peopleId<span class="token punctuation">,</span>seq <span class="token keyword">having</span> <span class="token function">count</span><span class="token punctuation">(</span><span class="token operator">*</span><span class="token punctuation">)</span><span class="token operator">&gt;</span><span class="token number">1</span><span class="token punctuation">)</span>
<span class="token comment">-- 查找表中多余的重复记录（多个字段），不包含rowid最小的记录</span>
<span class="token keyword">select</span> <span class="token operator">*</span> <span class="token keyword">from</span> vitae a
<span class="token keyword">where</span> <span class="token punctuation">(</span>a<span class="token punctuation">.</span>peopleId<span class="token punctuation">,</span>a<span class="token punctuation">.</span>seq<span class="token punctuation">)</span> <span class="token operator">in</span> <span class="token punctuation">(</span><span class="token keyword">select</span> peopleId<span class="token punctuation">,</span>seq <span class="token keyword">from</span> vitae <span class="token keyword">group</span> <span class="token keyword">by</span> peopleId<span class="token punctuation">,</span>seq <span class="token keyword">having</span> <span class="token function">count</span><span class="token punctuation">(</span><span class="token operator">*</span><span class="token punctuation">)</span> <span class="token operator">&gt;</span> <span class="token number">1</span><span class="token punctuation">)</span> <span class="token operator">and</span> rowid <span class="token operator">not</span> <span class="token operator">in</span> <span class="token punctuation">(</span><span class="token keyword">select</span> <span class="token function">min</span><span class="token punctuation">(</span>rowid<span class="token punctuation">)</span> <span class="token keyword">from</span> vitae <span class="token keyword">group</span> <span class="token keyword">by</span> peopleId<span class="token punctuation">,</span>seq <span class="token keyword">having</span> <span class="token function">count</span><span class="token punctuation">(</span><span class="token operator">*</span><span class="token punctuation">)</span><span class="token operator">&gt;</span><span class="token number">1</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="参考手册" tabindex="-1"><a class="header-anchor" href="#参考手册" aria-hidden="true">#</a> 参考手册</h2><ul><li>http://www.w3school.com.cn/sql/index.asp</li><li>http://www.1keydata.com/cn/sql/sql-count.php</li></ul>`,3);function w(h,g){const p=c("ExternalLinkIcon");return l(),i("div",null,[u,k,a("idoc:ignore:start"),m,a(" TOC "),v,a(" /TOC "),a("idoc:ignore:end"),b,s("p",null,[s("a",y,[n("转载"),r(p)])]),E])}const N=t(d,[["render",w],["__file","21-minutes-MySQL-basic-entry.html.vue"]]);export{N as default};
